INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Prompt-to-app generation$q$, $q$Describe an application or feature in plain English and Lovable generates a working React/TypeScript codebase to match.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Conversational iteration$q$, $q$Refine the app by continuing the chat, Lovable edits the underlying code and updates the live preview in response.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Supabase backend integration$q$, $q$Connect authentication, database tables, and storage through a native Supabase integration without writing backend code by hand.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Visual editor$q$, $q$Adjust layout, styling, and content directly on the canvas for quick tweaks that don't require a new prompt.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$GitHub sync and code export$q$, $q$Push the generated project to a GitHub repository so it stays under version control and can be handed off to developers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Custom domains$q$, $q$Connect a custom domain to a deployed Lovable app on paid plans instead of using the default subdomain.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$One-click deployment$q$, $q$Publish and host the finished app directly from the platform without configuring separate hosting infrastructure.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Figma import$q$, $q$Bring in existing designs from Figma as a starting point instead of prompting the layout from scratch.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Team workspaces$q$, $q$Collaborate on shared projects with teammates, with per-user credit controls and SSO available on higher tiers.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Generates a working full-stack app from a plain-language description in minutes$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Produces real, exportable React/TypeScript code rather than a locked-in proprietary format$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Native Supabase integration handles auth, database, and storage without manual backend setup$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Live preview and conversational editing make iteration fast for non-developers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$GitHub sync lets professional developers pick up and extend a project cleanly$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Credit-based pricing means real costs can exceed the advertised plan price under heavy use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Complex or highly custom business logic may still require manual coding cleanup$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Cloud hosting and certain AI features can add cost on top of the base subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Less precise control than hand-coding for developers who want exact implementation details$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$AI-generated output quality can vary depending on how the prompt is written$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$What is Lovable used for?$q$, $q$Lovable is used to build full-stack web applications, prototypes, internal tools, and client projects by describing them in natural language instead of writing code from scratch.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Is Lovable free to use?$q$, $q$Yes, Lovable offers a free plan with a limited monthly allotment of build credits. Paid plans unlock more credits, private projects, custom domains, and team features.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Do I need to know how to code to use Lovable?$q$, $q$No coding experience is required to get started, since apps are built through natural-language prompts and a visual editor, though basic technical knowledge helps when refining more complex projects.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Can I export the code Lovable generates?$q$, $q$Yes, Lovable generates a real React and TypeScript codebase that can be synced to GitHub, so the project isn't locked into the platform.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$What backend does Lovable use?$q$, $q$Lovable integrates natively with Supabase, providing authentication, a Postgres database, and storage for apps built on the platform.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Startup MVP prototyping$q$, $q$Founders describe a product idea and get a working, demoable app to validate with early users or investors before committing engineering resources.$q$, $q$Startup founders and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Internal business tools$q$, $q$Non-technical staff build lightweight dashboards, trackers, and forms to solve a specific operational need without waiting on IT.$q$, $q$Operations and business teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Client web apps for agencies$q$, $q$Freelancers and small agencies use Lovable to scaffold client websites and simple web apps quickly, then customize the generated code as needed.$q$, $q$Freelancers and small agencies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Personal and hackathon projects$q$, $q$Developers and hobbyists spin up quick side projects or hackathon entries by prompting a working app instead of setting up a project from scratch.$q$, $q$Individual developers and hobbyists$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Free$q$, $q$$0$q$, $q$monthly$q$, $q$["Daily build credits (up to a monthly cap)","Public projects","Access to the AI app builder and live preview","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Pro$q$, $q$From $25/month$q$, $q$monthly (annual billing available at a discount)$q$, $q$["Larger monthly credit allowance","Private projects","Custom domains","Code editing and export"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Business$q$, $q$From $50/month$q$, $q$monthly (annual billing available at a discount)$q$, $q$["Everything in Pro","SSO for team access","Data training opt-out","Per-user credit limits and restricted projects"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual contract$q$, $q$["Custom credit and usage commitments","Dedicated support","Advanced security and compliance options","Team and organization-wide administration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lovable is an AI-powered app builder that lets people describe what they want in plain English and get back a working web application, complete with a front end, backend logic, and a database connection. It grew out of an earlier project called GPT Engineer and relaunched under the Lovable name in 2023, based in Stockholm, Sweden, at a time when a wave of AI coding assistants were moving from autocomplete helpers toward tools that could generate entire applications on their own.$q$, $q$Instead of dragging widgets onto a canvas the way older no-code tools do, Lovable works through a conversational chat interface: you describe a feature or a fix, the platform generates or edits the underlying code, and you see the change rendered in a live preview a few seconds later. Iteration happens by continuing the conversation rather than hand-editing components, which lowers the barrier for people who have never opened a code editor before.$q$, $q$Under the hood, Lovable generates a real React and TypeScript codebase and can wire up a Supabase backend for authentication, storage, and database tables, so what comes out the other end is not a locked-in black box but a project that can be exported, pushed to GitHub, and handed off to a professional developer if the product outgrows its no-code origins. That combination of accessibility for beginners and a real codebase underneath has helped Lovable become one of the more widely used tools in the emerging AI app-builder category.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$who-lovable-is-for$q$, $q$Who Lovable Is For$q$, 2, ARRAY[$q$Lovable is aimed squarely at people who have a product idea and no engineering team to build it. Founders validating a concept, indie hackers shipping side projects, and product managers who want a clickable prototype before pulling in developers are the core audience, since a working demo can be built in an afternoon instead of a sprint.$q$, $q$It also appeals to designers and marketers who need a functional internal tool, landing page, or client-facing web app quickly, without waiting on a sprint backlog. Because it generates real code and can sync to GitHub, technical teams sometimes use it as a fast scaffolding step, letting Lovable produce a first draft that engineers then refine by hand rather than starting a new project from an empty repository.$q$, $q$Freelancers and small agencies building simple web apps or dashboards for clients are another natural fit, since Lovable's speed and low cost let them quote and deliver small projects that would otherwise not be worth a custom development engagement. Students and self-taught builders learning how full-stack apps fit together also use it as a way to see working examples of authentication, data, and UI code side by side.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams building large, highly regulated, or performance-critical systems should be cautious. AI-generated code can behave unpredictably on complex business logic, and Lovable's per-project structure is better suited to standalone apps than to a sprawling enterprise codebase with strict architecture requirements, code review standards, or long-term maintenance plans spanning many contributors.$q$, $q$Anyone who needs precise, line-by-line control over every implementation detail from day one may find the chat-driven workflow frustrating, since guiding the AI to an exact desired outcome can take more back-and-forth than simply writing the code directly, especially for intricate state management or performance-tuned interfaces.$q$, $q$Budget-conscious hobbyists building many small apps should also weigh the credit-based pricing carefully; heavier usage, custom domains, and cloud hosting can push real monthly costs well above the advertised entry price, so those who cannot tolerate variable costs may prefer a flat-fee alternative or a self-hosted stack they control end to end.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The centerpiece of Lovable is prompt-to-app generation: describe an application, page, or feature in natural language and Lovable scaffolds working React/TypeScript code, then keeps refining it as you continue the conversation. A live preview panel updates as changes are made, so there is no separate build step to see the result, and mistakes can be corrected simply by describing what should change.$q$, $q$Beyond the chat, Lovable includes a visual editing mode for tweaking layout and styling directly, native Supabase integration for authentication and database tables, one-click custom domain connection, and GitHub sync so the generated codebase stays under version control and can be handed off to developers at any point without a rewrite.$q$, $q$Team-oriented features round things out: shared workspaces, project collaboration, and, on higher plans, SSO and data-training opt-out for organizations with stricter security requirements. Support for importing designs from Figma and deploying finished apps directly from the platform is also part of the workflow, along with a credit-based usage system that scales with plan tier.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$the-lovable-experience$q$, $q$The Lovable Experience$q$, 2, ARRAY[$q$Using Lovable feels closer to briefing a junior developer than operating a drag-and-drop builder. A new project starts from a single prompt describing the app, and within moments a working scaffold appears in the preview pane, ready to be refined through further instructions instead of manual assembly.$q$, $q$The back-and-forth rhythm, prompt, preview, refine, is the core loop, and most of the day-to-day experience happens in that chat thread rather than in a traditional IDE, though the code and visual editors remain available for anyone who wants to step in directly and adjust something by hand.$q$, $q$Usage is metered through a credit system tied to the plan tier, which means the experience can shift from generous and frictionless on the free tier to a more deliberate, credit-conscious workflow for teams running larger or more frequent builds, where each substantial prompt is weighed against the credits it will consume.$q$]::text[], 4);
