INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Text-to-Video Generation$q$, $q$Generate short video clips directly from written prompts using Luma's Ray model family.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Image-to-Video Generation$q$, $q$Turn a single still image, such as a product photo or artwork, into an animated video clip.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Ray Model Family (Ray2/Ray3)$q$, $q$Successive generations of Luma's video models add reasoning-driven generation, HDR support, and improved motion realism.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Multi-Keyframe Direction$q$, $q$Set multiple reference frames within a single clip so the model interpolates motion and scene changes between them.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Character & Style Consistency$q$, $q$Maintain the same subject, character, or visual style across multiple generated shots for coherent multi-clip projects.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$HDR & 16-bit EXR Export$q$, $q$Export generated footage in production-ready formats for color grading and compositing in tools like Resolve or Nuke.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Draft Mode$q$, $q$Iterate quickly on rough, lower-fidelity generations before committing credits to a final high-quality render.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Dream Machine API$q$, $q$Programmatic access for developers to integrate image and video generation into their own applications.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Luma Agents Workspace$q$, $q$A team-oriented workspace with shared credits, project organization, and usage analytics for collaborative production.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Image Generation Model$q$, $q$A companion image-generation model alongside Ray video models for combined multimodal creative workflows.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$High-quality, cinematic motion and physically plausible video output$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Genuine free tier lets users test the product before committing to a paid plan$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Advanced creative controls, including multi-keyframe direction and HDR export, aimed at professional workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Developer-friendly API for building custom video and image generation features$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Frequent model updates (Ray2 to Ray3.2) that steadily improve output quality$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Commercial use and watermark removal require at least the Plus paid plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Credit-based pricing can be hard to predict for heavy or long-form usage$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Free tier's daily credit cap limits it to occasional, short clips only$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Like other generative video tools, output can include artifacts or inconsistent motion$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Team and Enterprise pricing requires contacting sales rather than transparent self-serve pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$What is Luma AI used for?$q$, $q$Luma AI is primarily used to generate short videos and images from text prompts or reference images through its Dream Machine platform, serving marketers, filmmakers, and developers alike.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Does Luma AI have a free plan?$q$, $q$Yes, Luma AI offers a genuine free tier with a limited daily credit allowance, though output includes a watermark and is restricted to personal, non-commercial use.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$How much does Luma AI cost?$q$, $q$Paid plans start at Plus for around $30/month (or about $25/month billed annually), with Pro and Ultra tiers offering more credits and usage, and Team/Enterprise pricing available on request.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Does Luma AI offer an API?$q$, $q$Yes, the Dream Machine API lets developers programmatically generate images and videos and integrate Luma's models into their own applications.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$What is Ray3?$q$, $q$Ray3 is Luma's advanced video generation model, adding reasoning-driven generation, native HDR support, multi-keyframe direction, and higher-resolution output compared to earlier Ray models.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Social Media and Marketing Video$q$, $q$Quickly produce short, polished video clips for ads, teasers, and social posts from a text prompt or a single product image.$q$, $q$Marketers and social media teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Film and VFX Previsualization$q$, $q$Use multi-keyframe direction and HDR/EXR export to explore shots and bring AI-generated footage into professional editing pipelines.$q$, $q$Filmmakers and VFX artists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Product and E-commerce Visualization$q$, $q$Animate product photos into engaging video content for online stores and marketing campaigns without a video shoot.$q$, $q$E-commerce brands and retailers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Custom App Integration$q$, $q$Build video or image generation features into a product using the Dream Machine API, paying based on usage rather than hosting models.$q$, $q$Developers and startups$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Limited daily credit allowance","Personal, non-commercial use only","Watermarked video exports","Access to core Dream Machine generation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Plus$q$, $q$$30/month (~$25/month billed annually)$q$, $q$Monthly or annual$q$, $q$["10,000 credits per month","Commercial use rights","Watermark removed","Guest edit access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Pro$q$, $q$$90/month (~$75/month billed annually)$q$, $q$Monthly or annual$q$, $q$["40,000 credits per month","4x Luma Agents usage","Everything included in Plus","Higher-volume production support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Ultra$q$, $q$$300/month (~$250/month billed annually)$q$, $q$Monthly or annual$q$, $q$["150,000 credits per month","15x Luma Agents usage","Everything included in Pro","Highest individual-tier usage limits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Luma AI, founded in 2021 and based in Palo Alto, California, builds AI tools for visual content creation, best known for its Dream Machine video generation platform and the Ray series of video models. What began as a startup focused on neural radiance fields (NeRF) and 3D capture from photos and video has evolved into a broader creative AI company spanning text-to-video, image-to-video, and increasingly agentic creative workflows.$q$, $q$Dream Machine, Luma's flagship product, lets users generate short video clips from text prompts, still images, or a combination of both, using models it calls Ray2 and Ray3. These models emphasize physically plausible motion, character and scene consistency across shots, and increasingly cinematic controls such as multi-keyframe direction, camera moves, and HDR-ready output aimed at production pipelines rather than just quick social clips.$q$, $q$Beyond the consumer-facing web app, Luma offers an API that lets developers integrate video and image generation into their own products, and it has begun packaging its tools as Luma Agents, a workspace model aimed at teams doing repeated creative production rather than one-off generations. The result is a platform that spans casual experimentation, professional content production, and developer integration under one brand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$who-its-for$q$, $q$Who Luma AI Is For$q$, 2, ARRAY[$q$Content creators, marketers, and social media teams who need short, polished video clips quickly are a core audience for Luma AI. Rather than shooting or editing traditional footage, they can turn a still image, a product photo, or a text description into a moving clip suitable for ads, teasers, or social posts, cutting production time significantly.$q$, $q$Filmmakers, animators, and VFX artists exploring AI-assisted previsualization also fit well. Features like multi-keyframe control, character reference, and HDR/EXR export are aimed squarely at people who need to bring AI-generated shots into professional editing and compositing tools like Resolve or Nuke, rather than treating the output as a finished deliverable.$q$, $q$Developers and product teams building AI-powered creative features are another natural fit, thanks to the Dream Machine API. Startups building video-generation front ends, design tools, or automated content pipelines can plug into Luma's models without training or hosting their own, paying based on usage rather than building infrastructure from scratch.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Users on a strict, ongoing zero-dollar budget who need frequent commercial-grade output will find Luma AI's model limiting. Watermark-free, commercially licensed video requires at least the Plus tier, and the free tier's daily credit allowance is only enough for occasional short clips, not for consistent production use.$q$, $q$Teams that need precise, frame-accurate control comparable to traditional animation or live-action shooting should also be cautious. Like other generative video tools, Luma AI can produce inconsistent results or unexpected motion, and it is not a substitute for the full manual control over blocking, timing, and continuity that a human production crew provides.$q$, $q$Businesses with heavy, sustained video generation needs may also find the credit-based system hard to predict. Because pricing scales with credits consumed per clip length, resolution, and model choice, teams generating large volumes of long-form or high-resolution video should budget carefully or lean on Team and Enterprise plans rather than assuming a flat monthly fee covers everything.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Text-to-video and image-to-video generation form the core of Dream Machine, letting users produce short clips from a written prompt, a single reference image, or both together, with the Ray model family tuned for realistic motion and scene coherence.$q$, $q$Multi-keyframe direction is a standout capability in newer Ray models, allowing creators to set multiple reference frames within a single clip so the model can interpolate motion, camera movement, and scene changes between them, giving more directorial control than a single prompt alone.$q$, $q$Professional export options, including HDR generation and 16-bit EXR output, let studios bring Luma-generated footage into standard color-grading and compositing pipelines, while the Dream Machine API and Luma Agents platform extend these capabilities to developers and teams through programmatic access, shared credits, and usage analytics.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$the-luma-ai-experience$q$, $q$The Luma AI Experience$q$, 2, ARRAY[$q$Using Luma AI typically starts in the browser, where the interface centers on a prompt box alongside optional image uploads, keyframe controls, and model selection. The experience is designed to feel approachable for newcomers while exposing deeper controls, like camera direction and keyframing, for users willing to dig in.$q$, $q$Generation times vary with model and settings, and Draft Mode gives users a faster, lower-fidelity way to iterate on an idea before committing credits to a higher-quality render. This iterative loop of quick draft, refine, then master mirrors how professional creative teams work and helps manage the cost of experimentation.$q$, $q$Overall, the platform reads as a tool that has grown from a research-driven 3D capture project into a fuller creative production suite, with the Dream Machine web app, mobile capture tools, and developer API together forming an ecosystem rather than a single point product.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
