INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Configurable and bundled products$q$, $q$Sell products with multiple variants (size, color) or grouped/bundled offerings, with flexible pricing and inventory rules per combination.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Multi-store and multi-currency$q$, $q$Run several storefronts, languages, and currencies from a single Magento installation, useful for brands operating across regions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Elasticsearch/OpenSearch catalog search$q$, $q$Built-in integration with Elasticsearch or OpenSearch powers fast, relevant product search and layered navigation on larger catalogs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$REST and GraphQL APIs$q$, $q$First-class APIs let developers build headless storefronts, mobile apps, or integrations with ERP, PIM, and CRM systems.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Page Builder$q$, $q$A drag-and-drop content editor for building landing pages, category pages, and CMS content without writing HTML.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Extension marketplace$q$, $q$A large library of third-party extensions and themes covering payments, shipping, marketing, and merchandising add-ons.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Modular architecture$q$, $q$Magento's module system lets developers extend or override core functionality cleanly without modifying core code directly.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Instant Purchase and persistent cart$q$, $q$Returning customers can check out faster with saved payment and shipping details, and carts persist across sessions.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Multi-source inventory (MSI)$q$, $q$Track and allocate stock across multiple warehouses or fulfillment locations from within the core platform.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$No software license fee; source code is free to download and modify$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Deep customization potential thanks to a modular, open codebase$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Handles complex catalogs, multi-store, and multi-currency setups well$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Large ecosystem of agencies, developers, and third-party extensions$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Maintained and security-patched by Adobe with an active open-source community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Requires self-managed hosting, server configuration, and ongoing maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Steep learning curve compared to hosted, no-code storefront builders$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Total cost of ownership can be high once hosting, extensions, and developer time are factored in$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Some advanced features (B2B, AI merchandising, staging) require Adobe Commerce or paid extensions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Upgrades and patching demand technical expertise to avoid breaking customizations$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Is Magento Open Source really free?$q$, $q$Yes, the software itself is free to download and use with no license fee. You still pay for hosting, developer time, extensions, and a domain, so total costs vary by project.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$What is the difference between Magento Open Source and Adobe Commerce?$q$, $q$Magento Open Source is the free, self-hosted core platform. Adobe Commerce is the paid edition built on the same codebase, adding native B2B tools, AI-driven merchandising, content staging, and optional managed cloud hosting.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Do I need a developer to run Magento Open Source?$q$, $q$For most stores, yes. Setup, hosting, security patching, and customization typically require PHP development experience or an agency partner, unlike fully hosted SaaS platforms.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Can Magento Open Source scale to a large catalog?$q$, $q$Yes, it's designed for merchants with large or complex catalogs, offering multi-store, multi-currency, and Elasticsearch/OpenSearch-powered search out of the box.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Is Magento Open Source still supported by Adobe?$q$, $q$Yes, Adobe continues to release security patches and updates for Magento Open Source alongside Adobe Commerce, since both share the same underlying codebase.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Custom storefront for a mid-market retailer$q$, $q$An agency builds a tailored storefront with custom product configurators and pricing logic that off-the-shelf SaaS platforms can't easily support.$q$, $q$Digital agencies and mid-market ecommerce brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Multi-region, multi-currency storefront$q$, $q$A brand operating in several countries runs one Magento instance serving multiple languages, currencies, and localized catalogs from a shared backend.$q$, $q$International or multi-brand retailers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Headless commerce backend$q$, $q$A development team uses Magento's REST/GraphQL APIs as the commerce engine behind a custom React or mobile front end.$q$, $q$Development teams building headless or omnichannel experiences$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Large or complex product catalog$q$, $q$A merchant with thousands of SKUs and configurable variants relies on Magento's catalog and search tools to keep navigation and merchandising manageable.$q$, $q$Retailers with large, complex, or highly variant product catalogs$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Magento Open Source$q$, $q$Free$q$, $q$N/A (self-hosted download)$q$, $q$["Full core ecommerce platform","Modular, customizable codebase","Community support and forums","Access to extension marketplace"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Adobe Commerce$q$, $q$Custom pricing$q$, $q$Annual license$q$, $q$["Everything in Open Source","Native B2B functionality","AI-driven merchandising and search","Content staging and preview","Adobe support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Adobe Commerce on Cloud$q$, $q$Custom pricing$q$, $q$Annual license$q$, $q$["Everything in Adobe Commerce","Managed cloud infrastructure","Built-in scaling and CDN","Dedicated environments for staging/production"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Magento Open Source is the free, self-hosted edition of the Magento ecommerce platform, now developed and maintained as part of Adobe Commerce. Built on PHP with a modular architecture, it gives merchants and developers full access to the codebase, letting them customize catalog logic, checkout flows, and storefront design without paying a software license fee.$q$, $q$The project traces back to 2007, when Los Angeles-based Varien released the first beta of Magento, followed by the open-source Community Edition in 2008. Magento changed hands several times, including a stint under eBay, before Adobe acquired it in 2018 and folded it into the Adobe Commerce family, where the free edition continues to be developed and patched.$q$, $q$Magento Open Source sits alongside the paid Adobe Commerce edition, which adds managed cloud hosting, B2B tools, and AI-driven merchandising on top of the same core. Open Source is generally chosen by smaller and mid-market retailers, developers, and agencies that want Magento's flexibility and depth without an enterprise licensing commitment.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$who-magento-open-source-is-for$q$, $q$Who Magento Open Source Is For$q$, 2, ARRAY[$q$It suits developers and digital agencies building bespoke storefronts for clients who need capabilities beyond what typical SaaS platforms offer, such as complex product configurations, layered navigation, or highly specific checkout logic that would require workarounds elsewhere.$q$, $q$Growing merchants who have outgrown simpler platforms are a natural fit, particularly those managing large catalogs, multiple storefronts, multiple currencies, or B2B-style pricing rules, and who need a platform that can scale in complexity as the business does.$q$, $q$It works best for organizations with an in-house developer or a reliable agency partner, since getting real value from Magento Open Source means being comfortable owning server management, security updates, and extension maintenance rather than relying on a vendor to handle it.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo founders or small teams without technical resources will likely find Magento Open Source frustrating, since there is no built-in hosting, and getting a store live requires configuring a server stack, Elasticsearch or OpenSearch, and Composer-based deployments.$q$, $q$Businesses that just want a quick, turnkey storefront with predictable monthly costs are usually better served by hosted platforms like Shopify or BigCommerce, where hosting, security, and uptime are handled automatically rather than left to the merchant.$q$, $q$Companies that need enterprise features such as native B2B account management, AI-powered recommendations, or content staging out of the box should look at Adobe Commerce instead, since replicating those capabilities in Open Source generally means paying for third-party extensions and extra development time.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Catalog and merchandising tools include configurable and bundled products, layered navigation, and catalog search powered by Elasticsearch or OpenSearch, giving stores with large or complex product ranges a solid foundation for organizing and surfacing inventory.$q$, $q$Checkout and order management support multi-currency and multi-language storefronts, guest checkout, persistent shopping carts, wishlists, and product comparison, along with extensible payment and shipping method integrations that developers can adapt to local markets.$q$, $q$Extensibility is central to the platform: a modular codebase, a marketplace of third-party extensions and themes, REST and GraphQL APIs for headless or omnichannel builds, and the Page Builder visual editor for assembling content without writing markup by hand.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$the-magento-open-source-experience$q$, $q$The Magento Open Source Experience$q$, 2, ARRAY[$q$Day-to-day, working with Magento Open Source feels closer to running a full web application than using a simple storefront builder. Initial setup involves provisioning a server stack, installing dependencies via Composer, and configuring search infrastructure before the storefront is even usable.$q$, $q$Once running, the ecosystem around it is a real advantage: a large base of specialized agencies, an active developer community, a marketplace of extensions, and regular security patches from Adobe help offset the platform's inherent complexity for teams willing to invest in it.$q$, $q$The overall trade-off is consistent: no license fee and near-total control over functionality, in exchange for a steeper learning curve and a total cost of ownership that includes hosting, development time, and ongoing maintenance that a hosted SaaS platform would otherwise absorb.$q$]::text[], 4);
