INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Drag-and-drop email builder$q$, $q$A visual editor with pre-built content blocks and templates for designing newsletters and campaigns without coding.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Marketing automation$q$, $q$Workflow builder that triggers emails based on subscriber behavior, form submissions, dates, or e-commerce events.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Landing pages and forms$q$, $q$Customizable landing pages, embedded forms, and pop-ups for capturing leads and growing subscriber lists.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Website builder$q$, $q$A simple built-in website builder for creating basic sites or blogs alongside email campaigns.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$E-commerce integrations$q$, $q$Native integrations with Shopify and WooCommerce for syncing products and sending targeted, revenue-tracked campaigns.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$AI writing assistant$q$, $q$AI-assisted content generation to help draft subject lines and email copy faster.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Subscriber segmentation$q$, $q$Group and target subscribers based on behavior, custom fields, and engagement history.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Reporting and analytics$q$, $q$Campaign performance dashboards covering opens, clicks, unsubscribes, and e-commerce revenue attribution.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Third-party integrations$q$, $q$Connections with WordPress, Zapier, Stripe, and other common tools to fit into existing workflows.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Generous free plan that includes automation, landing pages, and forms, not just basic email sending$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Clean, intuitive interface that requires little onboarding for non-technical users$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Affordable paid tiers compared to many competitors offering similar feature depth$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$All-in-one toolset (email, landing pages, website, forms) reduces the need for separate tools$q$, 3);
