INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Advanced customization (e.g., custom HTML editing) is reserved for higher-tier plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Pricing scales with subscriber count, which can add up quickly for fast-growing lists$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Some advanced reporting and segmentation features lag behind higher-priced competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Does MailerLite have a free plan?$q$, $q$Yes, MailerLite offers a free plan that includes a capped number of subscribers and monthly emails along with core features like campaigns, automation, a website, and signup forms.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$How is MailerLite pricing calculated?$q$, $q$Paid plans are based primarily on the number of active subscribers in your account and, on some tiers, the volume of emails sent; unsubscribed or bounced contacts are not counted.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Can I use MailerLite for e-commerce email marketing?$q$, $q$Yes, MailerLite integrates with platforms like Shopify and WooCommerce, allowing you to sync product catalogs and send targeted campaigns based on purchase behavior.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Does MailerLite support marketing automation?$q$, $q$Yes, it includes a workflow builder for automations triggered by subscriber actions, form submissions, dates, and e-commerce events, such as welcome sequences and abandoned cart emails.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Is MailerLite a good fit for large enterprises?$q$, $q$MailerLite offers a custom Enterprise plan for very large subscriber lists, but organizations needing deep CRM functionality or highly complex automation may find more specialized platforms a better fit.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Newsletter and content creator publishing$q$, $q$Writers, bloggers, and creators use MailerLite to design and send regular newsletters, capture new subscribers via landing pages and forms, and track engagement over time.$q$, $q$Independent creators and bloggers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Small e-commerce store marketing$q$, $q$Online stores sync product catalogs to send targeted promotional campaigns, abandoned cart reminders, and post-purchase follow-ups tied to revenue reporting.$q$, $q$Small to mid-sized online retailers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Lead generation for service businesses$q$, $q$Small businesses build landing pages and pop-up forms to capture leads, then nurture them through automated welcome and follow-up email sequences.$q$, $q$Freelancers and local service businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Startup and product launch communications$q$, $q$Early-stage startups use MailerLite's affordable plans to manage waitlists, announce product updates, and run onboarding email sequences without a large marketing budget.$q$, $q$Startups and small marketing teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Free$q$, $q$$0/month$q$, $q$Free forever$q$, $q$["Up to 250 subscribers","2,500 monthly emails","2 user seats","Campaigns, automations, landing pages, and signup forms","Basic website builder"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Comfort$q$, $q$From $12/month$q$, $q$Monthly (based on subscriber count)$q$, $q$["500 subscribers, 5,000 monthly emails","3 user seats","Premium templates","24/7 email support","Advanced automation triggers"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Power$q$, $q$From $25/month$q$, $q$Monthly (based on subscriber count)$q$, $q$["Everything in Comfort","Unlimited user seats","Custom HTML editor","AI writing assistant","Live chat support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, $q$["For 200,000+ subscribers","Dedicated success manager","Dedicated sending IP","Deliverability consulting and support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MailerLite is an email marketing and automation platform built around a simple idea: powerful tools shouldn't require a steep learning curve or an enterprise budget. Founded in 2010 in Vilnius, Lithuania, the company has grown into one of the more widely used email platforms for small and mid-sized businesses, largely on the strength of its clean interface and an unusually generous free plan.$q$, $q$At its core, MailerLite offers a drag-and-drop email builder, audience management, automation workflows, landing pages, pop-up forms, and a basic website builder, all bundled under one login. This bundling means a solo creator or small store can run campaigns, capture leads, and build a simple site without stitching together several separate tools.$q$, $q$The platform has steadily added features once considered premium elsewhere, including an AI writing assistant, automation triggers based on subscriber behavior, and e-commerce integrations for platforms like Shopify and WooCommerce. It positions itself against both entry-level tools like Mailchimp's free tier and mid-market platforms like ActiveCampaign, aiming to undercut both on price while matching much of their functionality.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$who-mailerlite-is-for$q$, $q$Who MailerLite Is For$q$, 2, ARRAY[$q$MailerLite is best suited to solopreneurs, bloggers, small e-commerce stores, and early-stage startups that need professional-looking email marketing without a steep monthly bill. Its free plan covers a meaningful set of subscribers and monthly sends, making it a realistic starting point rather than a stripped-down demo.$q$, $q$Content creators and course sellers who need landing pages, opt-in forms, and basic automation alongside email often find MailerLite's all-in-one approach convenient, since it removes the need to pay for a separate landing page tool while a list is still small.$q$, $q$Small marketing teams that value simplicity over deep customization also tend to do well here. Because the editor and automation builder are intentionally uncluttered, non-technical staff can build and send campaigns without much onboarding, which matters for teams without a dedicated email specialist.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Larger organizations with complex, multi-branch automation needs, heavy CRM-style segmentation, or advanced lead scoring may find MailerLite's automation builder comparatively limited next to platforms like ActiveCampaign or HubSpot, which are built around deeper marketing-ops workflows.$q$, $q$Enterprises with very large lists, strict compliance requirements, or a need for dedicated IPs and hands-on deliverability consulting outside the standard Enterprise tier may find that pricing and support scale less smoothly than with platforms purpose-built for large-scale senders.$q$, $q$Businesses that rely heavily on granular A/B testing across many variables, advanced predictive analytics, or deep native CRM functionality may also outgrow MailerLite and need to pair it with, or eventually migrate to, a more specialized marketing platform.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$MailerLite's core feature set spans campaign creation, subscriber management, and automation. The drag-and-drop email editor includes a library of templates, and a rich-text editor option for those who prefer writing without heavy design blocks. Automation workflows can be triggered by subscriber actions, form submissions, e-commerce events, or dates, letting users build welcome sequences, abandoned cart reminders, and re-engagement campaigns.$q$, $q$Beyond email, the platform includes landing pages, embedded and pop-up signup forms, and a basic website builder, all designed to funnel visitors into a managed subscriber list. E-commerce features let stores sync product catalogs and send targeted campaigns based on purchase history, while built-in reporting shows opens, clicks, and revenue attribution.$q$, $q$MailerLite also supports an AI writing assistant for drafting subject lines and copy, a custom HTML editor on higher tiers for advanced users, and integrations with common tools like Shopify, WooCommerce, WordPress, Zapier, and Stripe, giving it enough extensibility for most small-business tech stacks.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$the-mailerlite-experience$q$, $q$The MailerLite Experience$q$, 2, ARRAY[$q$Day-to-day, MailerLite feels deliberately uncluttered. The dashboard surfaces campaigns, subscribers, and automations without burying them under menus, and the email builder loads quickly with a straightforward block system that most users pick up within their first session.$q$, $q$Support and documentation lean toward self-service, with an extensive help center and live chat available on paid plans, while free-plan users generally rely on email support and community resources. Users frequently note that the platform feels fast and stable even as subscriber lists grow into the tens of thousands.$q$, $q$Overall, the experience trades some of the deep customization found in larger marketing suites for speed and clarity, which is consistent with MailerLite's stated goal of being an accessible, no-friction alternative to more complex email platforms.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
