INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Trust Flow & Citation Flow$q$, $q$Proprietary 0-100 scores that estimate the quality (Trust Flow) and quantity (Citation Flow) of links pointing to a URL, domain, or subfolder.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Site Explorer$q$, $q$The core research tool for drilling into a domain's backlinks, referring domains, anchor text profile, and topical link categories.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Fresh Index & Historic Index$q$, $q$Two separate crawl indexes—one continuously refreshed and one spanning many years—so users can compare current and historical link profiles.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Bulk Backlink Checker$q$, $q$Runs backlink and link-metric checks across many URLs at once, useful for auditing large link portfolios or vetting potential link partners.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Clique Hunter$q$, $q$Finds sites that link to multiple competitor domains but not to the user's own site, generating a targeted list of outreach prospects.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Topical Trust Flow$q$, $q$Categorizes a site's link profile by topic, helping users judge whether incoming links come from relevant, on-topic sources.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$API access$q$, $q$Exposes Majestic's link data programmatically for developers building custom dashboards, monitoring tools, or bulk analysis workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Majestic Million$q$, $q$A free, publicly available ranked list of the one million most-linked domains on the web, updated on a recurring basis.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Browser extension$q$, $q$A companion extension that surfaces Trust Flow and Citation Flow data for the page or site currently being viewed.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Deep, long-running historical link index that goes back further than many competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Trust Flow and Citation Flow provide a widely recognized, easy-to-compare shorthand for link quality$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Bulk checking and Clique Hunter make large-scale link auditing and prospecting efficient$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$API access allows link data to be integrated into custom tools and reporting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Free backlink checker and public Majestic Million list offer real value with no signup required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Limited to link intelligence, with no built-in keyword research, rank tracking, or content auditing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Interface and terminology assume prior SEO knowledge, which can be a hurdle for beginners$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Recurring subscription cost may be hard to justify for infrequent or single-site use$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Analysis Unit limits on lower plans can be consumed quickly during heavy bulk analysis$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Full historical data and API access require the more expensive Pro or API plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$What are Trust Flow and Citation Flow?$q$, $q$Trust Flow and Citation Flow are Majestic's proprietary link metrics, scored 0-100. Trust Flow estimates the quality and trustworthiness of a site's backlinks, while Citation Flow estimates the raw quantity or influence of those links.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Does Majestic offer a free version?$q$, $q$Majestic provides a free backlink checker with a limited number of Site Explorer lookups per day, along with the free public Majestic Million list, though full access requires a paid Lite, Pro, or API plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$What is the difference between the Lite, Pro, and API plans?$q$, $q$Lite offers basic Fresh Index and Site Explorer access with a smaller Analysis Unit allowance, Pro adds the Historic Index, Clique Hunter, and Bulk Backlink Checker with more units, and API adds full programmatic API access with the largest unit allowance.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Can I cancel or get a refund if Majestic isn't a fit?$q$, $q$Majestic offers a short money-back guarantee window for new subscribers on its Lite and Pro plans, allowing customers to request a refund if the service doesn't meet their needs shortly after signing up.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Does Majestic replace tools like Ahrefs or Semrush?$q$, $q$Not entirely. Majestic focuses specifically on backlink and link-authority data, so many users run it alongside broader SEO platforms that also cover keyword research, rank tracking, and technical audits.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Link profile auditing$q$, $q$Review a site's Trust Flow, Citation Flow, and referring domains to identify weak, spammy, or toxic links that may need disavowing.$q$, $q$SEO consultants and in-house SEO managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Competitor backlink research$q$, $q$Use Site Explorer and Clique Hunter to see which domains link to competitors and surface outreach opportunities the site doesn't yet have.$q$, $q$Digital marketing agencies and link-building teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Historical link investigation$q$, $q$Compare Fresh Index and Historic Index data to understand how a domain's link profile changed around a ranking drop, penalty, or migration.$q$, $q$SEO analysts and site owners recovering from ranking issues$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Bulk site vetting$q$, $q$Run the Bulk Backlink Checker across many domains at once to quickly assess link quality before accepting guest posts, sponsorships, or affiliate partners.$q$, $q$Link marketplaces, publishers, and affiliate program managers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Lite$q$, $q$$49.99/month$q$, $q$Monthly (annual billing available at a reduced rate)$q$, $q$["Fresh Index access","Limited Site Explorer","Smaller monthly Analysis Unit allowance","1 user seat"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Pro$q$, $q$$99.99/month$q$, $q$Monthly (annual billing available at a reduced rate)$q$, $q$["Historic Index access","Full Site Explorer","Clique Hunter and Bulk Backlink Checker","Larger monthly Analysis Unit allowance"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$API$q$, $q$$399.99/month$q$, $q$Monthly (annual billing available at a reduced rate)$q$, $q$["Full API access","Everything included in the Pro plan","Largest monthly Analysis Unit allowance","Multiple user seats"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Majestic is a backlink analysis and link intelligence tool built around one of the largest commercial indexes of hyperlinks on the web. Rather than trying to be an all-in-one SEO suite, Majestic focuses almost exclusively on link data: who is linking to a site, how those links have changed over time, and how trustworthy or influential those linking sources are considered to be. This narrow focus has made it a long-standing reference point for SEO professionals who need deep, historical backlink data rather than a broad marketing dashboard.$q$, $q$At the core of Majestic's offering are its two proprietary metrics, Trust Flow and Citation Flow, which estimate the quality and quantity of links pointing at a URL, subfolder, or domain. These scores, alongside tools like Site Explorer, Bulk Backlink Checker, and Clique Hunter, let users audit their own link profiles, investigate competitors, and identify link-building or link-removal opportunities. Majestic maintains both a Fresh Index of recently crawled links and a Historic Index that stretches back many years, which is one of its most distinctive advantages over newer competitors.$q$, $q$Majestic is typically used alongside, rather than instead of, broader SEO platforms. Many practitioners pair it with tools like Ahrefs, Semrush, or Moz for rank tracking and on-page audits, while relying on Majestic specifically for the depth and history of its link graph. It is delivered as a web application with API access for developers who want to pull link metrics into their own reporting tools or agency dashboards.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$who-majestic-is-for$q$, $q$Who Majestic Is For$q$, 2, ARRAY[$q$Majestic is best suited to SEO professionals, link-building specialists, and digital PR teams whose work centers on off-page authority rather than content or technical audits. Agencies that run link audits for clients, or that need to demonstrate the quality of a link-building campaign with concrete metrics, benefit from Majestic's Trust Flow and Citation Flow scores as an independent, third-party reference point.$q$, $q$The tool also suits researchers and analysts who need historical link data, such as investigating how a domain's backlink profile evolved before or after a penalty, migration, or algorithm update. Because Majestic's Historic Index goes back further than many competing tools, it is a common choice when a fresh crawl is not enough and past link activity must be reconstructed.$q$, $q$Developers and larger organizations that want to build custom reporting or monitoring systems are well served by the API plan, which exposes the same underlying link data programmatically. This makes Majestic a fit for teams that want to fold backlink metrics into internal dashboards, alerting systems, or bulk site-vetting workflows, such as those used in link marketplaces or affiliate vetting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Majestic is not a good fit for users looking for a single, all-purpose SEO platform. It does not offer the keyword research, rank tracking, or on-page content auditing features found in tools like Semrush or Ahrefs, so teams that need one dashboard for the entire SEO workflow will likely find Majestic too narrow on its own.$q$, $q$Beginners and casual website owners who just want a quick, occasional check of their site's backlinks may find the paid plans more than they need, especially since the interface leans on SEO-specific terminology like Trust Flow, Citation Flow, and Topical Trust Flow that assumes some existing familiarity with link metrics. Those users may be better served starting with Majestic's limited free checker before considering a subscription.$q$, $q$Budget-conscious freelancers or very small businesses that only need occasional link lookups may also hesitate at recurring monthly pricing when their needs could be met by ad hoc use of free tools. Similarly, teams whose SEO strategy is primarily technical or content-driven, with little focus on backlinks, are unlikely to get proportional value from a link-intelligence-first product like Majestic.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Majestic's flagship metrics, Trust Flow and Citation Flow, quantify link quality and link quantity on comparable 0-100 scales, giving users a fast way to judge the strength of a link profile without manually reviewing every referring domain. These scores are used throughout the platform, from Site Explorer summaries to bulk comparisons of many URLs at once.$q$, $q$Site Explorer is the primary research interface, letting users drill into a domain's backlinks, referring domains, anchor text distribution, and topical categories. The Bulk Backlink Checker extends this to dozens or hundreds of URLs simultaneously, which is useful for auditing large link portfolios or vetting prospective link partners at scale. Clique Hunter identifies sites that link to several competitors but not to the user's own site, surfacing concrete outreach targets.$q$, $q$Because Majestic maintains both a continuously updated Fresh Index and a long-running Historic Index, users can compare a site's current link profile against its history, which is valuable for diagnosing sudden ranking changes. An API and browser extension extend these capabilities into custom workflows and quick in-browser lookups, while the public Majestic Million list offers a free, ranked snapshot of the web's most-linked domains.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$majestic-experience$q$, $q$The Majestic Experience$q$, 2, ARRAY[$q$Using Majestic day to day feels utilitarian and data-dense rather than polished in the way of some newer SEO suites. The interface prioritizes tables, filters, and exportable reports over visual dashboards, which experienced link analysts tend to appreciate but newcomers may need time to adjust to. Reports load quickly given the scale of the underlying link index, and most core lookups, such as checking Trust Flow for a domain, take only a few clicks.$q$, $q$Account setup is straightforward, with self-service signup and monthly or annual billing options, plus a short window for new subscribers to request a refund if the paid plan does not meet their needs. The free backlink checker on the marketing site offers a limited but genuinely useful preview of the paid experience, letting prospective customers see Trust Flow, Citation Flow, and top anchor text data before committing to a subscription.$q$, $q$Support is available through documentation, help articles, and a ticketing system, and the product has a long operating history in the SEO space, which many users cite as reassurance around index stability and data continuity. Overall, the experience rewards users who already know what they are looking for in link data, offering depth and historical reach in exchange for a steeper initial learning curve than lighter-weight competitors.$q$]::text[], 4);
