INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Visual scenario builder$q$, $q$Build automations as a flowchart on a drag-and-drop canvas, making complex, branching logic easy to follow and edit.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Thousands of app integrations$q$, $q$Connect popular CRMs, spreadsheets, email tools, e-commerce platforms, and more through pre-built modules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Custom API and webhook modules$q$, $q$Use generic HTTP requests, webhooks, and custom API calls to integrate services that don't have a native connector.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Routers and branching logic$q$, $q$Split a single scenario into multiple conditional paths so different data can trigger different downstream actions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Data mapping and transformation tools$q$, $q$Iterators, aggregators, and built-in functions reshape, filter, and combine data as it flows between apps.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Error handling and retries$q$, $q$Attach error handlers, retry logic, and fallback routes to scenarios so failures don't silently break a workflow.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Scenario templates$q$, $q$Start from a library of pre-built templates for common automation patterns instead of building from scratch.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Execution logs and history$q$, $q$Inspect past runs and data bundles at each step to debug issues and understand exactly what happened in a scenario.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$AI modules and agents$q$, $q$Incorporate large language model steps and AI agent building blocks directly into automation workflows.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Scheduling and instant triggers$q$, $q$Run scenarios on a schedule or trigger them instantly via webhooks for near real-time automation.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Visual, flowchart-style builder makes complex multi-branch automations easier to understand than list-based tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Very wide reach through native integrations plus generic HTTP and webhook modules for almost any API$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Strong data mapping and transformation tools for reshaping information between apps$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Free plan and template library make it accessible to try before committing to a paid plan$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Detailed execution logs and error-handling options support serious debugging and reliability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Steeper learning curve than simpler, wizard-driven automation tools for first-time users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Usage-based operations/credits pricing can make costs less predictable for high-volume workflows$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Some advanced concepts (bundles, iterators, aggregators) require a bit of trial and error to master$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Very deep, vendor-certified integrations for specific enterprise systems may be thinner than dedicated point solutions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Complex scenarios with many modules can become visually cluttered and harder to navigate on the canvas$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Is Make free to use?$q$, $q$Yes, Make offers a free plan with a limited monthly allowance of operations/credits, which is enough for light automation use. Paid plans remove those limits and add features like higher execution priority and more credits.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$What was Make called before?$q$, $q$Make was previously known as Integromat. It was founded in 2012, acquired by Celonis in 2020, and rebranded as Make in 2022 as part of a broader repositioning of the product.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Do I need to know how to code to use Make?$q$, $q$No, Make is designed as a no-code visual builder, so most automations can be created by dragging and connecting modules. That said, comfort with concepts like JSON and APIs helps when working with custom HTTP requests or advanced data mapping.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$How is Make different from Zapier?$q$, $q$Both are automation platforms, but Make emphasizes a visual, flowchart-style canvas that shows branching logic and data flow directly, while Zapier traditionally favors a simpler, more linear step-by-step setup.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Can Make handle complex, multi-step business processes?$q$, $q$Yes, Make is built for scenarios with routers, loops, error handlers, and multiple branching paths, which makes it well suited to more elaborate workflows beyond simple one-to-one app connections.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Lead capture and CRM syncing$q$, $q$Automatically route new leads from forms, ads, or a website into a CRM, enrich the data, and notify the sales team.$q$, $q$Marketing and sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$E-commerce order and inventory automation$q$, $q$Sync orders, inventory levels, and shipping updates across an online store, fulfillment provider, and accounting tool.$q$, $q$E-commerce businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Client reporting and agency workflows$q$, $q$Build reusable, templated automations that pull client data from multiple sources into shared reports or dashboards.$q$, $q$Agencies and freelance automation consultants$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$AI-assisted content and data processing$q$, $q$Combine triggers, data transformations, and AI model calls to summarize, classify, or generate content as part of a workflow.$q$, $q$Operations and content teams adopting AI$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Free$q$, $q$$0$q$, $q$Forever free$q$, $q$["Limited monthly operations/credits allowance","Access to the visual scenario builder","Access to thousands of app integrations","Community templates and support forum"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Core$q$, $q$From around $9/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["Higher monthly operations/credits allowance","Unlimited active scenarios","Full-text search in execution history","Custom variables"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Pro$q$, $q$From around $16/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["Everything in Core","Priority scenario execution","Additional execution and logging capabilities","Higher operations/credits tiers available"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Teams / Enterprise$q$, $q$From around $29/month (Teams); custom pricing for Enterprise$q$, $q$Monthly, annual, or custom$q$, $q$["Multi-user access with team roles and permissions","Shared scenario templates across a team","SSO, SCIM, and audit logs (Enterprise)","Dedicated support and SLA options (Enterprise)"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Make is a visual automation and integration platform that lets people connect apps, move data, and orchestrate multi-step workflows without writing code. Originally launched in 2012 as Integromat, it was rebranded to Make in 2022 after being acquired by the process-mining company Celonis, and it now operates as its own product line focused on visual, no-code automation.$q$, $q$Where many automation tools present workflows as a linear list of steps, Make uses a drag-and-drop canvas where each automation, called a scenario, is built as a flowchart of connected modules. Branches, routers, loops, error handlers, and data aggregators can all be placed directly on the canvas, which makes it easier to see the logic of a complex process at a glance rather than scrolling through a stacked list of steps.$q$, $q$Make connects to thousands of apps and services through pre-built modules, plus generic HTTP, webhook, and API-request modules for anything without native support. It is commonly used to replace manual copy-paste work between tools such as CRMs, spreadsheets, email platforms, e-commerce systems, and AI services, and it scales from simple two-app automations to elaborate, branching business processes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$who-make-is-for$q$, $q$Who Make Is For$q$, 2, ARRAY[$q$Make is built for people who want to automate work without hiring a developer, but who also need more control and complexity than the simplest automation tools allow. Operations managers, marketers, agencies, and small business owners frequently use it to connect the everyday SaaS tools that run their business, such as CRMs, forms, spreadsheets, invoicing systems, and messaging apps.$q$, $q$It is also a strong fit for freelance automation consultants and agencies who build and sell workflows for clients, since scenarios can be templated, duplicated, and white-labeled across multiple accounts. Technically-minded users who are comfortable with concepts like JSON, HTTP requests, and API authentication get the most value, because Make exposes that level of detail when a native integration isn't available.$q$, $q$Teams that need visual clarity over a multi-branch process, such as lead routing, order fulfillment, content pipelines, or data syncing between several systems, tend to prefer Make's canvas view over simpler list-based automation tools once the workflow grows past a handful of steps.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Make is not the easiest starting point for someone who wants a one-click automation between two very common apps and has zero appetite for configuration. Simpler tools with more opinionated, wizard-style setups can get a basic automation running faster for users who never plan to touch anything more advanced than a single trigger-and-action pair.$q$, $q$Organizations with strict per-seat budgeting and unpredictable automation volume should also go in with clear eyes, since Make's plans are metered by operations or credits consumed rather than a flat unlimited-use fee, and heavy or inefficient scenarios can burn through an allowance faster than expected.$q$, $q$Finally, teams that need extremely deep, natively-built integrations with a very specific enterprise system, complete with vendor support and certification, may find that a specialized point solution or an enterprise iPaaS product serves that narrow need better than a general-purpose visual automation tool like Make.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Make is the visual scenario builder, a flowchart-style canvas where modules representing triggers and actions are connected with lines to define the flow of data. Routers let a scenario branch into multiple paths based on conditions, while error handlers, retries, and filters give builders fine-grained control over how a workflow behaves when something goes wrong.$q$, $q$Make supports thousands of app integrations alongside generic HTTP, webhook, and custom API modules, so almost any service with a public API can be incorporated even without a dedicated connector. Built-in data tools such as iterators, aggregators, array and text functions, and a mapping panel make it possible to transform and reshape data as it passes between apps.$q$, $q$Additional capabilities include a template library for common use cases, versioning and scenario history, execution logs for debugging, scheduled or instant (webhook-based) triggers, and AI-oriented modules for working with large language models and generating or processing content inside a workflow. Make also offers Make AI Agents and a broader set of building blocks for combining automation with AI reasoning steps.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$the-make-experience$q$, $q$The Make Experience$q$, 2, ARRAY[$q$Using Make feels closer to working in a diagramming tool than filling out a linear setup wizard. New scenarios start from a blank canvas or a template, and builders drag modules onto it, wire them together, and configure each one in a side panel that shows real data from previous steps for easy field mapping.$q$, $q$The learning curve is a bit steeper than the simplest automation tools, since concepts like modules, bundles, operations, and data structures take some getting used to. Once past that initial ramp-up, though, many users find the visual approach genuinely faster for building and troubleshooting anything beyond a trivial two-step automation, because the whole logic of the process is visible on one screen.$q$, $q$Day-to-day, the experience centers on iterating: running a scenario, inspecting the execution log or bundle output at each module, and adjusting mappings or adding routers and filters until the flow behaves correctly. Community templates, an active user forum, and in-app documentation help fill gaps when a particular integration or pattern isn't obvious at first.$q$]::text[], 4);
