INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$KWFinder keyword research$q$, $q$Finds long-tail, low-competition keyword suggestions with search volume, trend, and difficulty data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$SERPWatcher rank tracking$q$, $q$Tracks daily keyword rankings, including mobile and local results, with visual visibility trend reports.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$SERPChecker SERP analysis$q$, $q$Analyzes search results pages with competitor metrics like domain authority, backlinks, and social signals.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$LinkMiner backlink analysis$q$, $q$Audits backlink profiles, flags toxic or broken links, and surfaces link-building opportunities.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$SiteProfiler domain overview$q$, $q$Gives a quick snapshot of a domain's authority, estimated traffic, top keywords, and social metrics.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$AI Search Watcher$q$, $q$Monitors brand and site visibility within AI-generated search answers and overviews.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Browser extension$q$, $q$Overlays keyword volume, difficulty, and SEO metrics directly onto Google search results while browsing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Unified dashboard$q$, $q$Combines all Mangools tools under a single login and shared project workspace.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Local and multi-location tracking$q$, $q$Supports keyword and rank tracking across specific cities, regions, and search engines.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Affordable pricing compared to enterprise SEO suites$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Clean, beginner-friendly interface that's easy to learn quickly$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Strong long-tail keyword discovery in KWFinder$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Free plan and money-back guarantee lower the barrier to trying it$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$All tools share one login, making workflows feel cohesive$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Smaller keyword and backlink databases than premium competitors like Ahrefs or Semrush$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Rank-tracking and search limits can feel restrictive on lower-tier plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$No built-in technical site audit or content optimization scoring$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Limited third-party integrations and API access for advanced workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Free plan's search limits are quite low for regular use$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$What tools are included in Mangools?$q$, $q$A Mangools subscription includes KWFinder, SERPWatcher, SERPChecker, LinkMiner, SiteProfiler, and AI Search Watcher, all accessible from one shared dashboard and login.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Does Mangools have a free plan?$q$, $q$Yes. Mangools offers a permanent free plan with limited monthly searches, plus a short free trial with higher limits so new users can test the full feature set.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$How much does Mangools cost?$q$, $q$Paid plans start at roughly $29.90 per month when billed annually, with higher Premium and Agency tiers offering more searches, tracked keywords, and users.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Is Mangools good for beginners?$q$, $q$Yes. Mangools is widely regarded as one of the more approachable SEO tools, with a simplified interface aimed at users who are new to keyword research and rank tracking.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Is Mangools a good fit for large agencies or enterprises?$q$, $q$It can work for small agencies managing a handful of clients, but larger enterprises needing deep technical audits, huge data indexes, or extensive integrations may outgrow it.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Finding low-competition blog keyword ideas$q$, $q$Bloggers use KWFinder to identify long-tail keywords with decent search volume and manageable competition to target in new posts.$q$, $q$Bloggers and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Tracking client rankings for small agency accounts$q$, $q$Small agencies use SERPWatcher to monitor daily ranking changes across multiple client sites from a single dashboard.$q$, $q$Small SEO agencies and consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Auditing backlink profiles before outreach$q$, $q$Site owners use LinkMiner to review existing backlinks and identify link-building opportunities before running outreach campaigns.$q$, $q$Small business owners and marketers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Quick competitor and domain research$q$, $q$Freelance SEOs use SiteProfiler and SERPChecker to quickly evaluate a competitor's authority and ranking difficulty before pitching a strategy.$q$, $q$Freelance SEO consultants$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, $q$["Limited monthly KWFinder searches","Basic keyword suggestions","Access to core tool interfaces","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Basic$q$, $q$From $29.90/month$q$, $q$Billed annually (higher on monthly billing)$q$, $q$["Increased keyword search and rank tracking limits","Access to all five core tools","Single user, single project focus","Browser extension access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Premium$q$, $q$From $44.90/month$q$, $q$Billed annually (higher on monthly billing)$q$, $q$["Higher search, tracking, and project limits","Multiple team members supported","Priority customer support","Access to AI Search Watcher"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Agency$q$, $q$From $89.90/month$q$, $q$Billed annually (higher on monthly billing)$q$, $q$["Highest search and tracking limits","Most projects and team members included","Suited for managing multiple client sites","Full access to all Mangools tools"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mangools is a suite of SEO tools built in Bratislava, Slovakia, and launched in 2014 with a simple premise: keyword research and rank tracking shouldn't require an enterprise budget or a steep learning curve. The company built its reputation around KWFinder, a keyword research tool praised for surfacing long-tail, low-competition keywords in a clean, visual interface.$q$, $q$Over time, Mangools expanded into a full suite: KWFinder for keyword discovery, SERPWatcher for rank tracking, SERPChecker for SERP analysis, LinkMiner for backlink research, and SiteProfiler for quick domain and page authority checks. A newer addition, AI Search Watcher, tracks visibility in AI-generated search results. All five (now six) tools share one login, one dashboard, and one subscription.$q$, $q$Where competitors like Ahrefs or Semrush position themselves as all-in-one platforms for large teams and agencies, Mangools has stayed focused on approachability and price. It's frequently recommended as a starter SEO stack for bloggers, solo consultants, and small businesses that need reliable core data without the complexity or cost of enterprise suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$who-mangools-is-for$q$, $q$Who Mangools Is For$q$, 2, ARRAY[$q$Mangools is best suited to solo marketers, bloggers, freelance SEOs, and small business owners who need dependable keyword and rank data without paying for features they'll never use. Its interface prioritizes clarity over density, which makes it approachable for people new to SEO.$q$, $q$Small agencies and consultants managing a handful of client sites also find Mangools appealing, since the Agency plan bundles multiple projects and users at a fraction of what comparable seats cost on larger platforms. Content creators who mainly need to validate keyword ideas and track a modest set of rankings get most of what they need here.$q$, $q$Because pricing scales gently and the free plan has real (if limited) functionality, Mangools also works well for anyone testing whether investing in a paid SEO tool is worthwhile before committing to a bigger platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large in-house SEO teams and enterprise organizations that need extensive technical site audits, deep log-file analysis, or massive backlink and keyword index sizes will likely outgrow Mangools quickly. Its databases and crawl depth are smaller than those of dedicated enterprise platforms.$q$, $q$Agencies managing dozens of high-volume client accounts may also find the keyword and rank-tracking limits per plan restrictive compared to platforms built for scale, and Mangools does not offer the extensive third-party integrations or API depth that larger marketing operations often require.$q$, $q$Teams that need a single platform covering technical SEO audits, content optimization scoring, and PPC/paid-search data alongside organic SEO should look elsewhere, since Mangools deliberately stays focused on its core keyword, rank, SERP, and backlink toolset rather than trying to be a do-everything suite.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$KWFinder is the centerpiece: it surfaces keyword suggestions with search volume, keyword difficulty, and trend data, with a particular strength in finding long-tail, lower-competition terms. SERPWatcher tracks daily keyword rankings and visualizes visibility trends over time, including mobile and local tracking.$q$, $q$SERPChecker breaks down search results pages with metrics on domain authority, backlinks, and social shares for ranking competitors, helping users gauge how hard a keyword will be to rank for. LinkMiner analyzes backlink profiles, flags link-building opportunities, and estimates link strength, while SiteProfiler gives a fast overview of a domain's authority, traffic estimates, and social metrics.$q$, $q$The newer AI Search Watcher monitors how a site or brand appears in AI-generated answers across tools like Google's AI Overviews, reflecting the shift toward AI-influenced search visibility. All tools are tied together with a shared browser extension and a unified dashboard, so switching between keyword research and rank checks doesn't require jumping between separate logins or interfaces.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$the-mangools-experience$q$, $q$The Mangools Experience$q$, 2, ARRAY[$q$Using Mangools feels noticeably lighter than most SEO platforms. Dashboards favor charts and color-coded scores over dense spreadsheets, and most tasks (running a keyword search, checking a SERP, pulling a backlink report) take just a click or two from the shared navigation bar.$q$, $q$The onboarding experience is straightforward, and Mangools backs it with tutorials, an active blog, and a browser extension that overlays keyword and SEO metrics directly onto Google search results. Customer support has a reputation for being responsive, and the 48-hour money-back guarantee lowers the risk of trying a paid plan.$q$, $q$The trade-off for that simplicity is depth: power users accustomed to granular filters, custom reporting, and large-scale data exports in tools like Ahrefs may find Mangools comparatively lean. For its target audience, though, the experience trades some depth for speed and clarity, which is very much the point.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
